import{_ as e,o,c as n,a4 as s}from"./chunks/framework.B43MrHbS.js";const m=JSON.parse('{"title":"Component Patterns","description":"","frontmatter":{},"headers":[],"relativePath":"guide/components.md","filePath":"guide/components.md"}'),a={name:"guide/components.md"};function i(r,t,l,d,p,c){return o(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="component-patterns" tabindex="-1">Component Patterns <a class="header-anchor" href="#component-patterns" aria-label="Permalink to &quot;Component Patterns&quot;">​</a></h1><p>Components are the UI layer. They compose other components, consume data from the logic layer, and handle user interactions. These patterns apply across all frameworks.</p><h2 id="universal-principles" tabindex="-1">Universal Principles <a class="header-anchor" href="#universal-principles" aria-label="Permalink to &quot;Universal Principles&quot;">​</a></h2><ul><li><strong>Props in, events out</strong> — components receive data via props and communicate via events/callbacks</li><li><strong>Composition over inheritance</strong> — build complex UIs by composing small components</li><li><strong>Small components</strong> — keep components under 200 lines; decompose when larger</li><li><strong>Handle all states</strong> — loading, error, and empty states must be covered</li><li><strong>No heavy business logic</strong> — delegate to the logic layer (hooks, composables, services)</li></ul><h2 id="avoid-prop-drilling" tabindex="-1">Avoid Prop Drilling <a class="header-anchor" href="#avoid-prop-drilling" aria-label="Permalink to &quot;Avoid Prop Drilling&quot;">​</a></h2><p>When data needs to pass through multiple component levels, avoid threading props through intermediaries.</p><p>Each framework has its own solution:</p><table tabindex="0"><thead><tr><th>Framework</th><th>Composition</th><th>Shared context</th></tr></thead><tbody><tr><td>Vue</td><td>Slots</td><td>provide / inject</td></tr><tr><td>React</td><td>Children / render props</td><td>Context API</td></tr><tr><td>Next.js</td><td>Children / render props</td><td>Context API</td></tr><tr><td>SvelteKit</td><td>Slots / snippets</td><td>Context (getContext / setContext)</td></tr><tr><td>Angular</td><td>Content projection</td><td>Dependency injection</td></tr><tr><td>Nuxt</td><td>Slots</td><td>provide / inject</td></tr></tbody></table><p><strong>The principle is the same across all frameworks:</strong></p><ol><li><strong>Composition</strong> — let parent components inject content into child layout slots</li><li><strong>Context</strong> — share state through a scoped provider instead of passing props down</li></ol><h2 id="component-hierarchy" tabindex="-1">Component Hierarchy <a class="header-anchor" href="#component-hierarchy" aria-label="Permalink to &quot;Component Hierarchy&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Views (Pages)         → Composition, orchestration, provide context</span></span>
<span class="line"><span>  └── Layout          → Visual structure (slots / children)</span></span>
<span class="line"><span>      └── Features    → Feature logic (hooks, composables, stores)</span></span>
<span class="line"><span>          └── Shared  → Pure presentation (props in, events out)</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Type</th><th>Responsibility</th><th>Can have logic?</th><th>Can have state?</th></tr></thead><tbody><tr><td><strong>Views</strong></td><td>Compose components, provide context</td><td>Via logic layer</td><td>Yes (logic layer)</td></tr><tr><td><strong>Feature Components</strong></td><td>UI + feature logic</td><td>Via logic layer</td><td>Yes (logic layer)</td></tr><tr><td><strong>Shared Components</strong></td><td>Generic, reusable UI</td><td>Minimal (UI only)</td><td>Minimal (local)</td></tr></tbody></table><h2 id="size-limits" tabindex="-1">Size Limits <a class="header-anchor" href="#size-limits" aria-label="Permalink to &quot;Size Limits&quot;">​</a></h2><ul><li>Total component file: <strong>&lt; 200 lines</strong></li><li>Template / JSX: <strong>&lt; 100 lines</strong></li><li>If larger → decompose into sub-components</li></ul><h2 id="checklist" tabindex="-1">Checklist <a class="header-anchor" href="#checklist" aria-label="Permalink to &quot;Checklist&quot;">​</a></h2><ul><li>[ ] TypeScript with strict types</li><li>[ ] Typed props / inputs</li><li>[ ] Typed events / outputs</li><li>[ ] No prop drilling (use composition or context)</li><li>[ ] Loading / error / empty states handled</li><li>[ ] No business logic in the template / JSX</li><li>[ ] No raw HTML injection without sanitization</li></ul>`,17)])])}const u=e(a,[["render",i]]);export{m as __pageData,u as default};
